import type DeliveryCms from "src/delivery/DeliveryCms";
import { cachedResponseAsync, publicAssetCacheControl } from "src/server/compression";
import { generateStyleEntry } from "src/delivery/core/assets/buildStyle";
import { P9R_CACHE } from "src/socle/constants/p9r-constants";

/**
 * Serves the theme CSS generated by `core/assets/buildStyle`. Every rendered
 * public page links to this URL with a content-hash query (`?v=...`), so
 * editing the theme requires invalidating `P9R_CACHE.STYLE`.
 */
export default async function StyleServer(req: Request, delivery: DeliveryCms) {
    return cachedResponseAsync(
        req,
        P9R_CACHE.STYLE,
        delivery.cache,
        () => generateStyleEntry(delivery),
        publicAssetCacheControl(req),
    );
}
